SELECT 
FROM vso_order_transform t
WHERE t.row_valid = 1

    AND t.id = #{id}


    AND t.small_order_id = #{smallOrderId}


    AND t.formal_order_id = #{formalOrderId}

ORDER BY t.id DESC

SELECT FROM vso_order_transform t WHERE t.row_valid = 1
AND t.small_order_id = #{params.smallOrderId}
AND t.formal_order_id = #{params.formalOrderId}
AND (t.small_order_id = #{params.orderId} OR t.formal_order_id = #{params.orderId})
ORDER BY t.id DESC

SELECT COUNT(*)
FROM vso_order_transform t
WHERE t.row_valid = 1

    AND t.small_order_id = #{params.smallOrderId}


    AND t.formal_order_id = #{params.formalOrderId}

